/**
 * A visually persistent menu common in desktop applications that provides quick access to a consistent set of commands.
 *
 * ### Component Props
 *
 * See [Menubar props](https://www.radix-ui.com/primitives/docs/components/menubar) documentation for full details.
 *
 * | Prop            | Type                         | Default |
 * | :-------------- | :--------------------------- | :------ |
 * | _asChild_       | `boolean`                    | `false` |
 * | _defaultValue_  | `string`                     | -       |
 * | _value_         | `string`                     | -       |
 * | _onValueChange_ | `(value: string) => void`    | -       |
 * | _dir_           | `"ltr" \| "rtl"`             | -       |
 * | _loop_          | `boolean`                    | `false` |
 *
 *
 * ### Example Usage
 *
 * ```tsx
 * <Menubar>
 *   <MenubarMenu>
 *     <MenubarTrigger>File</MenubarTrigger>
 *     <MenubarContent>
 *       <MenubarItem>New Tab</MenubarItem>
 *       <MenubarItem>New Window</MenubarItem>
 *       <MenubarSeparator />
 *       <MenubarItem>Print</MenubarItem>
 *     </MenubarContent>
 *   </MenubarMenu>
 * </Menubar>
 * ```
 *
 * ### Accessibility (WCAG 2.2 AA)
 *
 * @wcag 2.1.1 Keyboard â€” arrow keys navigate between menus and items; Enter/Space activates; Escape closes.
 * @wcag 2.4.7 Focus Visible â€” focused items render an inset focus ring (`focus:ring-2 focus:ring-ring focus:ring-inset`) in addition to `bg-accent`, guaranteeing a visible 3:1 indicator against `bg-popover` in all themes (dark `--accent` and `--popover` otherwise collide at ~1:1).
 * @wcag 4.1.2 Name, Role, Value â€” `menubar`, `menu`, and `menuitem` roles via Radix Menubar primitives.
 */
function Menubar({
  className,
  ...props
}: React.ComponentProps<typeof MenubarPrimitive.Root>) {
  return (
    <MenubarPrimitive.Root
      data-slot="menubar"
      className={cn(
        'flex h-9 items-center gap-1 rounded border bg-background p-1 shadow-raised',
        className
      )}
      {...props}
    />
  );
}

